+/// Test if a pair of floating-point compares with a shared operand and 2
+/// constants has an empty set intersection, full set union, or if one compare
+/// is a superset of the other.
+static Value *simplifyAndOrOfFCmpsWithConstants(FCmpInst *Cmp0, FCmpInst *Cmp1,
+                                                bool IsAnd) {
+  // Look for this pattern: {and/or} (fcmp X, C0), (fcmp X, C1)).
+  if (Cmp0->getOperand(0) != Cmp1->getOperand(0))
+    return nullptr;
+  if (Cmp0->getPredicate() != Cmp1->getPredicate())
+    return nullptr;
+
+  const APFloat *C0, *C1;
+  if (!match(Cmp0->getOperand(1), m_APFloat(C0)) ||
+      !match(Cmp1->getOperand(1), m_APFloat(C1)))
+    return nullptr;
+
+  FCmpInst::Predicate Pred = Cmp0->getPredicate();
+
+  // Compare the constants to determine range relationships
+  int Cmp = C0->compare(*C1);
+  bool C0Less = (Cmp == APFloat::cmpLessThan);
+  bool C0Greater = (Cmp == APFloat::cmpGreaterThan);
+
+  // For ordered comparisons (olt, ole, ogt, oge), determine containment
+  // For unordered comparisons (ult, ule, ugt, uge), same logic applies
+  // since both include NaN in the same way
+  switch (Pred) {
+  default:
+    break;
+  case FCmpInst::FCMP_OLT:
+  case FCmpInst::FCMP_UOLT:
+  case FCmpInst::FCMP_OLE:
+  case FCmpInst::FCMP_UOLE:
+    // X < C or X <= C: larger constant means larger range
+    if (C0Less)
+      return IsAnd ? Cmp0 : Cmp1;  // smaller range for AND, larger for OR
+    if (C0Greater)
+      return IsAnd ? Cmp1 : Cmp0;
+    break;
